// 包根 +esm 的 MUI 子模块 import shape 损坏；standalone 构建内含一致的 React/MUI 图并导出 renderVoyager
const el = document.getElementById('voyager'); el.style.height = `${spec.height ?? 560}px`; el.textContent = 'Loading schema…';
const css = Object.assign(document.createElement('link'), { rel: 'stylesheet', href: 'https://cdn.jsdelivr.net/npm/graphql-voyager@2.1.0/dist/voyager.css' }); document.head.appendChild(css);
const { renderVoyager, sdlToSchema } = await import('https://cdn.jsdelivr.net/npm/graphql-voyager@2.1.0/dist/voyager.standalone.js/+esm');
const { sdl, ...props } = data; el.textContent = ''; renderVoyager(el, { ...props, introspection: sdlToSchema(sdl) });

