// standalone 保证单一 React/MUI 图；静态 CSS 与本次新建的 Emotion style 都搬入 shadow
const el = document.createElement('div'); el.style.height = `${spec.height ?? 560}px`; el.textContent = 'Loading schema…'; shadowRoot.appendChild(el);
const style = document.createElement('style'); style.textContent = await fetch('https://cdn.jsdelivr.net/npm/graphql-voyager@2.1.0/dist/voyager.css').then(r => r.text()); shadowRoot.prepend(style);
const before = new Set(document.head.querySelectorAll('style')); const moveStyles = () => { for (const s of document.head.querySelectorAll('style')) if (!before.has(s)) shadowRoot.appendChild(s); }; const observer = new MutationObserver(moveStyles); observer.observe(document.head, { childList: true });
const { renderVoyager, sdlToSchema } = await import('https://cdn.jsdelivr.net/npm/graphql-voyager@2.1.0/dist/voyager.standalone.js/+esm');
const { sdl, ...props } = data; el.textContent = ''; renderVoyager(el, { ...props, introspection: sdlToSchema(sdl) }); setTimeout(() => { moveStyles(); observer.disconnect(); }, 500);

